'use strict';

/**
* Create an array filled with false values and having a specified length.
*
* @module @stdlib/array-falses
*
* @example
* var falses = require( '@stdlib/array-falses' );
*
* var arr = falses( 2 );
* // returns <BooleanArray>[ false, false ]
*
* @example
* var falses = require( '@stdlib/array-falses' );
*
* var arr = falses( 2, 'generic' );
* // returns [ false, false ]
*/

// MODULES //

var main = require( './main.js' );


// EXPORTS //

module.exports = main;
